// Extract and normalize the incoming request payload
const body = $input.first().json.body || {};

if (!body.deal_id) throw new Error('Missing required field: deal_id');
if (!body.output_type) throw new Error('Missing required field: output_type');

return [{
  json: {
    deal_id: body.deal_id,
    output_type: body.output_type,
    recipient_email: body.recipient_email || null,
    recipient_name: body.recipient_name || null,
    instructions: body.instructions || '',
    requested_by: body.requested_by || 'manual',
    preview_mode: body.preview_mode === true || body.preview_mode === 'true'
  }
}];

// Merge deal context, output history, and build RAG queries for the output type
const req = $('Code: Normalize Request').first().json;
const dealRows = $('Postgres: Get Deal + Health').all();
const historyRows = $('Postgres: Get Output History').all();

const deal = dealRows[0]?.json || {};

if (!deal.deal_id) {
  throw new Error(`Deal not found: ${req.deal_id}`);
}

// Format output history
const historyText = historyRows.length > 0
  ? historyRows.map(r => {
      const h = r.json;
      const date = h.sent_at ? h.sent_at.toString().split('T')[0] : 'unknown';
      const to = h.recipient_name || h.recipient_email || 'unknown';
      return `- ${date}: [${h.output_type}] TO: ${to} — "${h.subject || '(no subject)'}" — ${h.content_summary || '(no summary)'}`;
    }).join('\n')
  : 'No previous outputs have been generated for this deal.';

// P2V2C2 summary string
const p2v2c2Summary = [
  `Pain: ${deal.pain_score || 0}/5`,
  `Power: ${deal.power_score || 0}/5`,
  `Vision: ${deal.vision_score || 0}/5`,
  `Value: ${deal.value_score || 0}/5`,
  `Change: ${deal.change_score || 0}/5`,
  `Control: ${deal.control_score || 0}/5`,
  `Total: ${deal.p2v2c2_total || 0}/30`
].join(' | ');

// RAG queries tailored to output type
const co = deal.company_name;
const outputType = req.output_type;

const ragQueryBank = {
  follow_up_email: [
    `What was discussed in the most recent call or meeting with ${co}? What were the key outcomes and next steps agreed?`,
    `What specific action items or commitments did Austin and ${co} make at the last touchpoint? What follow-ups are outstanding?`,
    `What pain, urgency, or business problems has ${co} expressed that should be referenced in a follow-up communication?`,
    `What Clearwater services or solutions were proposed or discussed with ${co}?`
  ],
  pre_call_planner: [
    `What are the key open questions, risks, and outstanding action items with ${co} going into the next meeting?`,
    `What pain and urgency has ${co} articulated? What power dynamics and executive sponsor access exists?`,
    `What is the current state and desired future state for ${co}'s cybersecurity and compliance program?`,
    `Who are the key stakeholders at ${co}? What are their goals, titles, and decision-making roles?`,
    `What Clearwater services and engagement approach has been discussed with ${co}?`,
    `What objections, competitive threats, or obstacles exist in the ${co} deal?`
  ],
  internal_team_update: [
    `What happened in the most recent call or meeting with ${co}? What were the key discussion points and outcomes?`,
    `What is the deal status with ${co}? What are the current P2V2C2 signals and executive sponsor dynamics?`,
    `What are the open risks, next steps, and action items for the ${co} deal?`,
    `What PE or board-level pressure or executive sponsor dynamics exist in the ${co} deal?`
  ],
  circle_back: [
    `What was the last communication or meeting with ${co}? How long ago was contact made?`,
    `What pain or urgency did ${co} express? What was the last agreed next step?`,
    `What Clearwater services were discussed with ${co}? What value proposition was presented?`
  ],
  meeting_confirm: [
    `What is the agenda and objectives for the upcoming meeting with ${co}?`,
    `What action items and next steps were agreed with ${co} that this meeting is meant to address?`,
    `Who are the key attendees and their roles at ${co} for the upcoming meeting?`
  ],
  approach_pdf: [
    `What is ${co}'s current cybersecurity and compliance posture? What gaps and pain points exist?`,
    `What future state has been co-created with ${co}? What are their compliance goals and desired capabilities?`,
    `What Clearwater services have been proposed or discussed for ${co}? What is the recommended engagement scope?`,
    `What is the key value proposition and ROI for ${co} working with Clearwater?`,
    `Who are the key stakeholders at ${co} and what are their individual success criteria?`,
    `What are the key risks and objections in the ${co} deal that the Approach Document should address?`
  ]
};

const queries = ragQueryBank[outputType] || ragQueryBank.follow_up_email;

return queries.map((query, i) => ({
  json: {
    deal_id: req.deal_id,
    output_type: req.output_type,
    recipient_email: req.recipient_email,
    recipient_name: req.recipient_name,
    instructions: req.instructions,
    requested_by: req.requested_by,
    preview_mode: req.preview_mode,
    company_name: co,
    deal,
    history_text: historyText,
    p2v2c2_summary: p2v2c2Summary,
    rag_query: query,
    rag_index: i
  }
}));

// Assemble all RAG results into a unified context block
const allSearchResults = $input.all();
const allQueryItems = $('Code: Merge Context + Build RAG Queries').all();
const baseData = allQueryItems[0].json;

const chunks = [];

allSearchResults.forEach((item, i) => {
  const results = item.json.result || [];

  results
    .filter(r => (r.score || 0) > 0.25)
    .forEach(r => {
      const p = r.payload || {};
      const date = p.date_created ? new Date(p.date_created).toISOString().split('T')[0] : 'unknown date';
      chunks.push(`[${p.doc_type || 'document'}, ${date}]\n${p.page_content || ''}`);
    });
});

// Dedupe chunks by content
const seen = new Set();
const uniqueChunks = chunks.filter(c => {
  const key = c.slice(0, 100);
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

const ragContext = uniqueChunks.length > 0
  ? uniqueChunks.join('\n\n---\n\n')
  : 'No relevant deal content found in Qdrant for this deal.';

return [{
  json: {
    deal_id: baseData.deal_id,
    output_type: baseData.output_type,
    recipient_email: baseData.recipient_email,
    recipient_name: baseData.recipient_name,
    instructions: baseData.instructions,
    requested_by: baseData.requested_by,
    preview_mode: baseData.preview_mode,
    company_name: baseData.company_name,
    deal: baseData.deal,
    history_text: baseData.history_text,
    p2v2c2_summary: baseData.p2v2c2_summary,
    rag_context: ragContext
  }
}];

