  ${sq(d.deal_id)},
  ${sq(d.output_type)},
  ${sq(d.recipient_email)},
  ${sq(d.recipient_name)},
  ${sq(d.subject)},
  ${sq(d.content_summary)},
  ${sq(d.body)},
  NOW(),
  ${sq(d.requested_by)},
  ${sq(status)}
) RETURNING id`;

return [{ json: { ...d, insert_sql: sql } }];

