// Parse Claude's JSON response with fallback
const response = $input.first().json;
const rawText = response.content?.[0]?.text || response.text || '{}';
const ctx = $('Code: Build Claude Prompt').first().json;

let generated;
try {
  const cleaned = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  generated = JSON.parse(cleaned);
} catch(e) {
  throw new Error('Failed to parse Claude output response: ' + e.message + '\nRaw (first 500): ' + rawText.slice(0, 500));
}

return [{
  json: {
    deal_id: ctx.deal_id,
    output_type: ctx.output_type,
    recipient_email: ctx.recipient_email || 'austin.holland@clearwatersecurity.com',
    recipient_name: ctx.recipient_name || 'Austin Holland',
    company_name: ctx.company_name,
    requested_by: ctx.requested_by,
    preview_mode: ctx.preview_mode,
    subject: generated.subject || `[CW Output] ${ctx.output_type} — ${ctx.company_name}`,
    body: generated.body || rawText,
    content_summary: generated.content_summary || '(no summary)',
    model_used: ctx.model
  }
}];

// Build INSERT SQL for outputs_log
// status = 'draft' for preview_mode, 'sent' for direct send
// RETURNING id so we can reference the draft later for approval
const d = $input.first().json;

function sq(val) {
  if (val === null || val === undefined || val === '') return 'NULL';
  return "'" + String(val).replace(/'/g, "''") + "'";
}

const status = d.preview_mode ? 'draft' : 'sent';

const sql = `INSERT INTO outputs_log (
  deal_id, output_type, recipient_email, recipient_name,
  subject, content_summary, full_content,
  sent_at, triggered_by, status
) VALUES (
  ${sq(d.deal_id)},
  ${sq(d.output_type)},
  ${sq(d.recipient_email)},
  ${sq(d.recipient_name)},
  ${sq(d.subject)},
  ${sq(d.content_summary)},
  ${sq(d.body)},
  NOW(),
  ${sq(d.requested_by)},
  ${sq(status)}
) RETURNING id`;

return [{ json: { ...d, insert_sql: sql } }];

// Capture the RETURNING id from the INSERT and merge with output data
const pgResult = $input.first().json;
const parsed = $('Code: Parse Output').first().json;
const insertNode = $('Code: Build Insert SQL').first().json;

// Postgres node returns the RETURNING row directly in json
const draft_id = pgResult.id || pgResult[0]?.id || null;

return [{
  json: {
    ...parsed,
    draft_id,
    preview_mode: insertNode.preview_mode
  }
}];

