// Parse approval request
const body = $input.first().json.body || {};

if (!body.draft_id) throw new Error('Missing required field: draft_id');

return [{
  json: {
    draft_id: parseInt(body.draft_id, 10),
    // Optional: Austin can override the body (after editing in chat)
    override_body: body.final_body || null
  }
}];

// Merge the fetched draft with any override body from the approval request
const draftRow = $input.first().json;
const approveReq = $('Code: Parse Approve Request').first().json;

if (!draftRow.id) {
  throw new Error(`Draft not found for id: ${approveReq.draft_id}`);
}

if (draftRow.status !== 'draft') {
  throw new Error(`Output ${approveReq.draft_id} is not in draft status (current: ${draftRow.status}). Cannot approve.`);
}

// Use override body if Austin edited the draft, otherwise use stored content
const finalBody = approveReq.override_body || draftRow.full_content;

return [{
  json: {
    draft_id: draftRow.id,
    deal_id: draftRow.deal_id,
    output_type: draftRow.output_type,
    recipient_email: draftRow.recipient_email,
    recipient_name: draftRow.recipient_name,
    subject: draftRow.subject,
    body: finalBody,
    was_edited: approveReq.override_body !== null
  }
}];

